#!/usr/bin/env bash
# apply-mobile-fix-and-fee.sh
# Ships: (1) mobile date-field overflow fix on recurring-maintenance forms
#        (2) remove returning-client 3% fee-waiver display from client dashboard
# Run:  bash ~/Desktop/Website/apply-mobile-fix-and-fee.sh
set -e
cd ~/Desktop/freddy-fixit

write() { # $1 = path, $2 = b64
  mkdir -p "$(dirname "$1")"
  printf '%s' "$2" | base64 --decode > "$1"
  echo "  wrote $1"
}

echo "Applying files..."
write "src/pages/ClientOnboarding.tsx" ""
write "src/components/NewRequest.tsx" ""
write "src/pages/ClientDashboard.tsx" ""

echo "Committing & pushing..."
git add -A
git commit -m "Fix mobile date-field overflow on recurring forms; remove returning-client fee-waiver display" || { echo "nothing to commit"; exit 0; }
git push
echo "✅ Changes committed & pushed. Hard-refresh (Cmd+Shift+R) after Vercel redeploys."
